<?php declare(strict_types=1);use App\Support\View;$base='/projects/'.$project->id.'/work-packages';?>
<?php if($canManage):$configurationSection='work-packages';include __DIR__.'/../projects/_configure_nav.php';endif;?>
<div class="d-flex justify-content-between align-items-start mb-4"><div><p class="text-secondary mb-1"><?= View::escape($project->displayTitle()) ?></p><h1>Work Packages</h1></div><?php if($canManage):?><a class="btn btn-primary" href="<?= View::escape($urls->to($base.'/create',$configurationYear===null?[]:['year'=>$configurationYear])) ?>">Add Work Package</a><?php endif;?></div>
<form class="card card-body mb-4" method="get"><div class="row g-3"><div class="col-lg-4"><label class="form-label" for="search">Search</label><input class="form-control" id="search" name="search" value="<?= View::escape($filters['search']) ?>" placeholder="Code, title, or responsible person"></div><div class="col-sm-4 col-lg-2"><label class="form-label" for="active">State</label><select class="form-select" id="active" name="active"><?php foreach(['all'=>'All','active'=>'Active','inactive'=>'Inactive']as$v=>$l):?><option value="<?= $v ?>" <?= $filters['active']===$v?'selected':'' ?>><?= $l ?></option><?php endforeach;?></select></div><div class="col-sm-4 col-lg-3"><label class="form-label" for="responsibility">Responsibility</label><select class="form-select" id="responsibility" name="responsibility"><?php foreach(['all'=>'All','assigned'=>'Assigned','unassigned'=>'Unassigned']as$v=>$l):?><option value="<?= $v ?>" <?= $filters['responsibility']===$v?'selected':'' ?>><?= $l ?></option><?php endforeach;?></select></div><div class="col-sm-4 col-lg-3"><label class="form-label" for="responsible_participant_id">Responsible participant</label><select class="form-select" id="responsible_participant_id" name="responsible_participant_id"><option value="">All participants</option><?php foreach($options as$o):?><option value="<?= $o->id ?>" <?= $filters['responsible_participant_id']===(string)$o->id?'selected':'' ?>><?= View::escape($o->personName()) ?></option><?php endforeach;?></select></div><div class="col-sm-4 col-lg-2"><label class="form-label" for="year">Overlap year</label><input class="form-control" id="year" name="year" inputmode="numeric" value="<?= View::escape($filters['year']) ?>"></div><div class="col-lg-2 d-flex align-items-end"><button class="btn btn-outline-primary w-100">Filter</button></div></div></form>
<?php if($page->items===[]):?><div class="card card-body text-secondary">No Work Packages have been configured for this project.</div><?php else:?><div class="table-responsive bg-white border rounded"><table class="table table-striped align-middle mb-0"><thead><tr><th>Code</th><th>Title</th><th>Dates</th><th>Responsible participant</th><th>State</th><th>Warnings</th><th>Actions</th></tr></thead><tbody><?php foreach($page->items as$wp):?><tr><td><a href="<?= View::escape($urls->to($base.'/'.$wp->id)) ?>"><?= View::escape($wp->code) ?></a></td><td><?= View::escape($wp->title) ?></td><td><?= View::escape($wp->period()) ?></td><td><?= View::escape($wp->responsibleName()) ?></td><td><?= $wp->isActive?'Active':'Inactive' ?></td><td><?php foreach($wp->warnings()as$warning):?><span class="text-warning-emphasis d-block"><?= View::escape($warning) ?></span><?php endforeach;?></td><td><?php if($canManage):?><a class="btn btn-sm btn-outline-primary" href="<?= View::escape($urls->to($base.'/'.$wp->id.'/edit',$configurationYear===null?[]:['year'=>$configurationYear])) ?>">Edit</a><?php endif;?></td></tr><?php endforeach;?></tbody></table></div><?php endif;?>
<?php if($page->pageCount()>1):?><nav class="mt-3" aria-label="Work Package pages"><ul class="pagination"><?php for($n=1;$n<=$page->pageCount();$n++):?><li class="page-item <?= $n===$page->page?'active':'' ?>"><a class="page-link" href="<?= View::escape($urls->to($base,array_merge($filters,['page'=>$n]))) ?>"><?= $n ?></a></li><?php endfor;?></ul></nav><?php endif;?>
